// evolution_instance vem da Edge (por barbearia ou master). Base Evolution SEM $env.
const EVOLUTION_BASE_DEFAULT = 'http://72.60.159.183:8080';
const body = $input.first().json;
const clients = body.clients || [];
if (clients.length === 0) return [];
let base = String(EVOLUTION_BASE_DEFAULT);
if (base.endsWith('/')) base = base.slice(0, -1);

return clients.map((c) => {
  const inst = String(c.evolution_instance || 'caio_zap').trim().replace(/[^a-zA-Z0-9_-]/g, '') || 'caio_zap';
  const sendUrl = base + '/message/sendText/' + inst;
  const fullName = c.full_name || 'Cliente';
  const message = '📅 *BookNow*\n\nOlá, ' + fullName + '!\n\nJá faz um tempinho desde seu último atendimento. Que tal agendar um novo horário?\n\nAbra o app e reserve seu horário. Até lá!';
  return { json: { phone: c.phone, full_name: fullName, message, sendUrl, evolution_instance: inst } };
});
